class FenwickTree {
    private size: number;
    private tree: number[];

    constructor(size: number) {
        this.size = size;
        this.tree = new Array(size + 1).fill(0); // 1-based indexing
    }

    update(index: number, delta: number): void {
        while (index <= this.size) {
            this.tree[index] += delta;
            index += index & -index;
        }
    }

    query(index: number): number {
        let res = 0;
        while (index > 0) {
            res += this.tree[index];
            index -= index & -index;
        }
        return res;
    }
}

function solve(nums: number[], queries: number[][]): number[] {
    const n = nums.length;
    const depths = nums.map(x => getDepth(x));
    const ft = new Array(4).fill(0).map(() => new FenwickTree(n));

    for (let i = 0; i < n; i++) {
        const d = depths[i];
        ft[d].update(i + 1, 1);
    }

    const answer: number[] = [];

    for (const q of queries) {
        if (q[0] === 1) {
            const l = q[1], r = q[2], k = q[3];
            if (k < 0 || k > 3) {
                answer.push(0);
                continue;
            }
            const count = ft[k].query(r + 1) - ft[k].query(l);
            answer.push(count);
        } else {
            const idx = q[1], val = q[2];
            const oldVal = nums[idx];
            const oldD = depths[idx];
            ft[oldD].update(idx + 1, -1);
            nums[idx] = val;
            const newD = getDepth(val);
            ft[newD].update(idx + 1, 1);
            depths[idx] = newD;
        }
    }

    return answer;
}

function getDepth(x: number): number {
    if (x === 1) return 0;
    let steps = 0;
    let current = x;
    while (current !== 1) {
        current = countSetBits(current);
        steps++;
        if (current === 1) {
            return steps;
        }
    }
    return steps;
}

function countSetBits(x: number): number {
    return x.toString(2).split('1').length - 1;
}
